const geminiRaw = $input.first().json;
const prevData = $('Build Gemini Prompt').first().json;

const aiText = geminiRaw?.candidates?.[0]?.content?.parts?.[0]?.text ?? 'No summary available';
const d = prevData;
const reportDate = d.report_date ? d.report_date.toString().substring(0, 10) : 'N/A';

const sleepQualityMap = { 1: 'Excellent', 2: 'Good', 3: 'Fair', 4: 'Poor', 5: 'Very Poor' };
const sleepQualityLabel = d.sleep_quality ? (sleepQualityMap[d.sleep_quality] ?? d.sleep_quality) : '—';

const htmlEmail = `<!DOCTYPE html><html><body style="font-family:-apple-system,Arial,sans-serif;background:#f5f5f5;padding:20px;margin:0">
<div style="max-width:600px;margin:0 auto;background:white;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.1)">
  <div style="background:linear-gradient(135deg,#1a1a2e,#16213e);color:white;padding:24px;text-align:center">
    <h2 style="margin:0;font-size:22px">🏃 Daily Health Report</h2>
    <p style="margin:4px 0 0;opacity:.7;font-size:13px">${reportDate} · Helio → Zepp → Intervals.icu → Gemini</p>
  </div>
  <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;padding:20px">
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#1a1a2e">${d.steps ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">STEPS</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#1a1a2e">${d.calories ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">CALORIES</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#e63946">${d.resting_hr ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">RESTING HR</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#4361ee">${d.hrv_avg ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">HRV (ms)</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#2a9d8f">${d.sleep_hours ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">SLEEP HRS</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#f4a261">${d.sleep_score ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">SLEEP SCORE</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#1a1a2e">${d.workout_count ?? 0}</div><div style="font-size:10px;color:#888;margin-top:3px">WORKOUTS</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#1a1a2e">${d.workout_avg_hr ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">AVG HR</div></div>
    <div style="background:#f8f9fa;border-radius:8px;padding:12px;text-align:center"><div style="font-size:22px;font-weight:700;color:#1a1a2e">${d.weight ?? '—'}</div><div style="font-size:10px;color:#888;margin-top:3px">WEIGHT kg</div></div>
  </div>
  ${d.workout_names ? `<div style="padding:0 20px 12px">
    <div style="background:#fff8e7;border-left:3px solid #f4a261;padding:10px 14px;border-radius:0 6px 6px 0;font-size:13px;color:#555">
      🏋️ <strong>Workouts:</strong> ${d.workout_names}
    </div>
  </div>` : ''}
  <div style="padding:0 20px 20px">
    <div style="background:#f0f4ff;border-left:4px solid #4361ee;padding:16px;border-radius:0 8px 8px 0;font-size:14px;line-height:1.7;color:#333;white-space:pre-wrap">${aiText}</div>
  </div>
  <div style="background:#f8f9fa;padding:12px;text-align:center;font-size:11px;color:#aaa">
    Amazfit Helio Strap → Zepp → Intervals.icu → n8n → Gemini → You
  </div>
</div></body></html>`;

const whatsappMsg = `🏃 Health Report — ${reportDate}

👟 Steps: ${d.steps ?? 'N/A'}
🔥 Calories: ${d.calories ?? 'N/A'} kcal
❤️ Resting HR: ${d.resting_hr ?? 'N/A'} bpm
🧠 HRV: ${d.hrv_avg ?? 'N/A'} ms
😴 Sleep: ${d.sleep_hours ?? 'N/A'}h (Score: ${d.sleep_score ?? 'N/A'}/100)
🏋️ Workouts: ${d.workout_count ?? 0} sessions

${aiText}`;

return [{ json: { htmlEmail, whatsappMsg, report_date: reportDate } }];
